sql:
SELECT exoplanet_id 
FROM exoplanets 
WHERE discovery_year > 2010 AND habitability_index > 0.7;

SELECT exoplanets.exoplanet_id, exoplanets.discovery_year, methods.method_name
FROM exoplanets
JOIN methods ON exoplanets.method_id = methods.method_id;

external_knowledge:
- Significant research articles are those with an impact factor of 5.0 or higher;
- Long-term orbiting planets have an orbital period greater than 365 days;
- The secondary role refers to the 'secondary' role in the project.

sql:
SELECT habitability_index, COUNT(*) AS exoplanet_count
FROM exoplanets
GROUP BY habitability_index;

SELECT role, last_updated
FROM project_exoplanets
WHERE project_id = 0 AND exoplanet_id = 0;

SELECT COUNT(exoplanet_id)
FROM exoplanets
WHERE habitability_index > (SELECT AVG(habitability_index) FROM exoplanets);

SELECT DISTINCT r.name, o.exoplanet_id
FROM researchers r
JOIN observations o ON r.researcher_id = o.researcher_id;

SELECT exoplanet_id, habitability_index
FROM exoplanets
WHERE habitability_index > (
  SELECT AVG(habitability_index) FROM exoplanets
);

SELECT DISTINCT r.name
FROM researchers r
INNER JOIN observations o ON r.researcher_id = o.researcher_id;
